//! Validates that `NativeLlamaPipeline::embed_chunk` routes through
//! `ColumnarEmbedBackend::fetch_row` (sparse fast-path) instead of
//! `fetch_tensor("token_embd.weight")` (full ~260 MB materialize).
//!
//! The check is structural: a tracking dense backend records every
//! `fetch_tensor` call against the embed tensor name. After
//! `embed_chunk(&[1, 2, 3])` the recorder must show ZERO embed-tensor
//! `fetch_tensor` calls (the columnar backend's `fetch_row` is what gets
//! the bytes). If we regress to the legacy materialize path the recorder
//! flips and the test fails — preventing the 99.998 % bandwidth-savings
//! claim from quietly reverting.
//!
//! Construction details:
//!   - Synthetic HCEM (vocab=16, hidden=8, bf16) so row contents are
//!     deterministic and we can assert per-row values.
//!   - TrackingDense backend that returns zeros for any non-embed tensor
//!     the pipeline needs at construction time, and increments a counter
//!     if anyone ever asks for `token_embd.weight`.
//!   - Minimal `KnotConfig` (1 layer, tiny dims) so `from_knot` succeeds
//!     without a real model. We do NOT actually invoke `forward_one` —
//!     `embed_chunk` is the surface under test and it doesn't touch
//!     attention/FFN weights.

#![cfg(not(target_arch = "wasm32"))]

use std::collections::HashMap;
use std::io::Write;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

use distributed_inference::columnar_embed_backend::{
    ColumnarEmbedBackend, HCEM_DTYPE_BF16, HCEM_HEADER_BYTES, HCEM_MAGIC, HCEM_VERSION,
};
use distributed_inference::loader::{
    KnotConfig, KnotWeights, OwnedBytes, TensorInfo, WeightBackend,
};
use distributed_inference::model::NativeLlamaPipeline;

/// Dense backend stand-in. Counts how many times each tensor name is
/// asked for. Returns zero-filled bytes of the metadata-declared length so
/// pipeline construction doesn't blow up on missing attention/FFN tensors.
struct TrackingDense {
    embed_calls: AtomicUsize,
    metadata: HashMap<String, TensorInfo>,
}

impl WeightBackend for TrackingDense {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        if name == "token_embd.weight" || name == "output.weight" {
            self.embed_calls.fetch_add(1, Ordering::SeqCst);
        }
        let info = self
            .metadata
            .get(name)
            .ok_or_else(|| format!("tracking dense: no '{}'", name))?;
        Ok(OwnedBytes::Owned(Arc::new(vec![0u8; info.length as usize])))
    }
    fn has_tensor(&self, name: &str) -> bool {
        self.metadata.contains_key(name)
    }
    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
    fn tensor_info(&self, name: &str) -> Option<TensorInfo> {
        self.metadata.get(name).cloned()
    }
}

fn write_synthetic_hcem(path: &std::path::Path, vocab: u32, hidden: u32) -> std::io::Result<()> {
    let bpe = 2usize; // bf16
    let mut buf = Vec::with_capacity(HCEM_HEADER_BYTES + vocab as usize * hidden as usize * bpe);
    buf.extend_from_slice(HCEM_MAGIC);
    buf.extend_from_slice(&HCEM_VERSION.to_le_bytes());
    buf.extend_from_slice(&vocab.to_le_bytes());
    buf.extend_from_slice(&hidden.to_le_bytes());
    buf.push(HCEM_DTYPE_BF16);
    // Zero-fill reserved bytes (HCEM_HEADER_BYTES - 17 = 15).
    for _ in 0..(HCEM_HEADER_BYTES - 17) {
        buf.push(0);
    }
    // Each row: a recognizable byte = (token_id as u8) + 0x40.
    for token_id in 0..vocab {
        let seed = (token_id as u8).wrapping_add(0x40);
        for _ in 0..(hidden as usize * bpe) {
            buf.push(seed);
        }
    }
    let mut f = std::fs::File::create(path)?;
    f.write_all(&buf)?;
    Ok(())
}

fn build_tracking_dense(
    vocab: usize,
    hidden_dim: usize,
    num_layers: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    intermediate: usize,
) -> TrackingDense {
    let mut metadata: HashMap<String, TensorInfo> = HashMap::new();
    // Embed + tied lm_head + final norm.
    metadata.insert(
        "token_embd.weight".to_string(),
        TensorInfo {
            offset: 0,
            length: (vocab * hidden_dim * 4) as u64,
            tensor_type: "f32".to_string(),
            shape: None,
        },
    );
    metadata.insert(
        "output.weight".to_string(),
        TensorInfo {
            offset: 0,
            length: (vocab * hidden_dim * 4) as u64,
            tensor_type: "f32".to_string(),
            shape: None,
        },
    );
    metadata.insert(
        "output_norm.weight".to_string(),
        TensorInfo {
            offset: 0,
            length: (hidden_dim * 4) as u64,
            tensor_type: "f32".to_string(),
            shape: None,
        },
    );
    // Per-layer tensors with realistic GGUF names. The pipeline resolves
    // these during `resolve_all`; missing names panic at construction.
    let qkv_dim = num_heads * head_dim;
    let kv_dim = num_kv_heads * head_dim;
    for l in 0..num_layers {
        for (name, len) in [
            (format!("blk.{}.attn_norm.weight", l), hidden_dim * 4),
            (format!("blk.{}.attn_q.weight", l), hidden_dim * qkv_dim * 4),
            (format!("blk.{}.attn_k.weight", l), hidden_dim * kv_dim * 4),
            (format!("blk.{}.attn_v.weight", l), hidden_dim * kv_dim * 4),
            (
                format!("blk.{}.attn_output.weight", l),
                qkv_dim * hidden_dim * 4,
            ),
            (format!("blk.{}.ffn_norm.weight", l), hidden_dim * 4),
            (
                format!("blk.{}.ffn_gate.weight", l),
                hidden_dim * intermediate * 4,
            ),
            (
                format!("blk.{}.ffn_up.weight", l),
                hidden_dim * intermediate * 4,
            ),
            (
                format!("blk.{}.ffn_down.weight", l),
                intermediate * hidden_dim * 4,
            ),
        ] {
            metadata.insert(
                name,
                TensorInfo {
                    offset: 0,
                    length: len as u64,
                    tensor_type: "f32".to_string(),
                    shape: None,
                },
            );
        }
    }
    TrackingDense {
        embed_calls: AtomicUsize::new(0),
        metadata,
    }
}

#[test]
fn embed_chunk_uses_fetch_row_not_full_materialize() {
    let tmp = std::env::temp_dir().join(format!("hcem-sparse-path-{}.bin", std::process::id()));
    let vocab = 16u32;
    let hidden = 8u32;
    write_synthetic_hcem(&tmp, vocab, hidden).expect("write synthetic hcem");

    let dense = Arc::new(build_tracking_dense(
        vocab as usize,
        hidden as usize,
        /* num_layers */ 1,
        /* num_heads */ 2,
        /* num_kv_heads */ 2,
        /* head_dim */ 4,
        /* intermediate */ 16,
    ));
    let dense_clone: Arc<dyn WeightBackend> = dense.clone();
    let columnar = ColumnarEmbedBackend::from_mmap(tmp.to_str().unwrap(), dense_clone.clone())
        .expect("open hcem mmap");
    let backend: Arc<dyn WeightBackend> = Arc::new(columnar);

    // Snapshot metadata from the tracking dense for KnotWeights — same map
    // the tracking backend uses, so resolve_tensor sees all the names.
    let metadata = dense.metadata.clone();
    let config = KnotConfig {
        hidden_dim: hidden as usize,
        num_layers: 1,
        num_heads: 2,
        num_kv_heads: 2,
        head_dim: 4,
        intermediate_size: 16,
        vocab_size: vocab as usize,
        rms_norm_eps: 1e-5,
        rope_theta: 10_000.0,
        arch: "llama".to_string(),
        final_logit_softcap: None,
        query_pre_attn_scalar: None,
        sliding_window_pattern: None,
        sliding_window: None,
        global_head_dim: None,
        global_num_kv_heads: None,
        rope_local_base_freq: None,
        rope_scaling_factor: None,
        rope_partial_factor: None,
        d_state: None,
        d_conv: None,
        ssm_expand: None,
        dt_rank: None,
        rwkv_n_heads: None,
        rwkv_low_rank_w: None,
        rwkv_low_rank_a: None,
        rwkv_low_rank_v: None,
        rwkv_gate_inner: None,
        hybrid_attn_layer_period: None,
        max_seq_len: None,
        num_experts: None,
        num_experts_per_tok: None,
    };
    let knot = KnotWeights::from_parts(backend, metadata, Some(config), 0);
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 1.0);

    // Sanity: no embed tensor calls yet.
    assert_eq!(
        dense.embed_calls.load(Ordering::SeqCst),
        0,
        "pre-call counter must be 0"
    );

    let out = pipeline
        .embed_chunk(&[1u32, 2u32, 3u32], 0)
        .expect("embed_chunk");
    assert_eq!(out.len(), 3 * hidden as usize);

    // Token 1's row in the synthetic HCEM is bytes 0x41 0x41 ... (bf16).
    // bf16 with bits 0x4141 0000 = upper 16 bits 0x4141, lower zero.
    // As f32 bits 0x41410000 ≈ 12.0625 — finite, recognizable.
    let expected_bits = (0x4141u32) << 16;
    let expected = f32::from_bits(expected_bits);
    assert!(
        out[0..hidden as usize].iter().all(|&v| v == expected),
        "token 1 row should decode to bf16(0x4141) repeating; got first={}",
        out[0]
    );

    // The critical assertion: tracking dense must NEVER have seen a fetch
    // for the embed tensor. The ColumnarEmbedBackend intercepts owned
    // tensors before delegating, and the model now calls fetch_row not
    // fetch_tensor, so neither path can land on the dense recorder.
    assert_eq!(
        dense.embed_calls.load(Ordering::SeqCst),
        0,
        "sparse fast-path regression: embed_chunk hit the dense fetch_tensor counter"
    );

    // Microbench: report per-call timings so a manual run sees the
    // sparse-path latency profile (cold first call, warm cache hit,
    // cold new-tokens). The numbers here are tiny (vocab=16, hidden=8)
    // but the pattern matches the production claim — cache hits are
    // ~zero-cost, cold rows are one mmap slice each.
    let t1 = std::time::Instant::now();
    let _ = pipeline.embed_chunk(&[1, 2, 3], 0).unwrap();
    let cold_first_us = t1.elapsed().as_micros();
    let t2 = std::time::Instant::now();
    let _ = pipeline.embed_chunk(&[1, 2, 3], 0).unwrap();
    let warm_hit_us = t2.elapsed().as_micros();
    let t3 = std::time::Instant::now();
    let _ = pipeline.embed_chunk(&[10, 11, 12], 0).unwrap();
    let cold_new_us = t3.elapsed().as_micros();
    println!(
        "[sparse-bench] cold_first={}us warm_hit={}us cold_new_tokens={}us",
        cold_first_us, warm_hit_us, cold_new_us
    );

    let _ = std::fs::remove_file(&tmp);
}

/// Production-scale smoke: same sparse-path validation but against the
/// REAL qwen-embed.hcem in rknots/ (vocab=151,936, hidden=896, bf16 →
/// 260 MB matrix). Skipped if the file isn't present.
#[test]
fn embed_chunk_sparse_path_qwen_embed_hcem_when_present() {
    let path = std::path::Path::new(
        "./open-source/gnosis/distributed-inference/rknots/qwen-embed.hcem",
    );
    if !path.exists() {
        eprintln!("skipping qwen-embed.hcem smoke (file not present)");
        return;
    }

    // Real qwen2.5-0.5b dims.
    let vocab = 151_936usize;
    let hidden = 896usize;
    let dense = Arc::new(build_tracking_dense(
        vocab, hidden, /* num_layers */ 1, /* num_heads */ 14, /* num_kv_heads */ 2,
        /* head_dim */ 64, /* intermediate */ 4864,
    ));
    let dense_clone: Arc<dyn WeightBackend> = dense.clone();
    let columnar = ColumnarEmbedBackend::from_mmap(path.to_str().unwrap(), dense_clone.clone())
        .expect("open real qwen-embed.hcem");
    let backend: Arc<dyn WeightBackend> = Arc::new(columnar);

    let metadata = dense.metadata.clone();
    let config = KnotConfig {
        hidden_dim: hidden,
        num_layers: 1,
        num_heads: 14,
        num_kv_heads: 2,
        head_dim: 64,
        intermediate_size: 4864,
        vocab_size: vocab,
        rms_norm_eps: 1e-5,
        rope_theta: 10_000.0,
        arch: "llama".to_string(),
        final_logit_softcap: None,
        query_pre_attn_scalar: None,
        sliding_window_pattern: None,
        sliding_window: None,
        global_head_dim: None,
        global_num_kv_heads: None,
        rope_local_base_freq: None,
        rope_scaling_factor: None,
        rope_partial_factor: None,
        d_state: None,
        d_conv: None,
        ssm_expand: None,
        dt_rank: None,
        rwkv_n_heads: None,
        rwkv_low_rank_w: None,
        rwkv_low_rank_a: None,
        rwkv_low_rank_v: None,
        rwkv_gate_inner: None,
        hybrid_attn_layer_period: None,
        max_seq_len: None,
        num_experts: None,
        num_experts_per_tok: None,
    };
    let knot = KnotWeights::from_parts(backend, metadata, Some(config), 0);
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 1.0);

    // Cold first 3-token embed.
    let t0 = std::time::Instant::now();
    let _ = pipeline.embed_chunk(&[1u32, 2u32, 3u32], 0).unwrap();
    let cold_first_us = t0.elapsed().as_micros();

    // Warm cache hit.
    let t1 = std::time::Instant::now();
    let _ = pipeline.embed_chunk(&[1u32, 2u32, 3u32], 0).unwrap();
    let warm_us = t1.elapsed().as_micros();

    // Cold new tokens.
    let t2 = std::time::Instant::now();
    let _ = pipeline.embed_chunk(&[100u32, 200u32, 300u32], 0).unwrap();
    let cold_new_us = t2.elapsed().as_micros();

    println!(
        "[qwen-embed-sparse-bench] cold_first={}us warm_hit={}us cold_new_tokens={}us",
        cold_first_us, warm_us, cold_new_us
    );

    assert_eq!(
        dense.embed_calls.load(Ordering::SeqCst),
        0,
        "qwen-embed sparse regression: dense fetch_tensor counter is non-zero"
    );
}
